# AI Capital MVP - Stage 5 Frontend: Islamic Finance UI
# Adds /islamic-finance page, sidebar nav item, and i18n keys

Write-Host "=== STAGE 5 FRONTEND: Islamic Finance UI ===" -ForegroundColor Cyan
Write-Host ""

$ROOT = "C:\ai-capitalS-mvp"
Set-Location $ROOT

function Deploy-Base64File {
    param([string]$Base64, [string]$FilePath)
    $dir = Split-Path $FilePath -Parent
    if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    $bytes = [System.Convert]::FromBase64String($Base64)
    [System.IO.File]::WriteAllBytes($FilePath, $bytes)
    Write-Host "  [OK] $FilePath" -ForegroundColor Green
}

# ============================================================
# 1. Create the page component
# ============================================================
Write-Host "1. Creating islamic-finance page..." -ForegroundColor Yellow

$b64_page = ""

Deploy-Base64File -Base64 $b64_page -FilePath "$ROOT\frontend\app\islamic-finance\page.tsx"

# ============================================================
# 2. Add navigation item to Sidebar.tsx
# ============================================================
Write-Host ""
Write-Host "2. Updating Sidebar.tsx..." -ForegroundColor Yellow

$sidebarPath = "$ROOT\frontend\components\Sidebar.tsx"
$sidebarContent = Get-Content $sidebarPath -Raw -Encoding UTF8

if ($sidebarContent -match "islamic-finance") {
    Write-Host "  [SKIP] islamic-finance already in Sidebar.tsx" -ForegroundColor DarkYellow
} else {
    # Add islamic finance nav item in the 'research' group, after dueDiligence
    $navItem = @"
      { labelKey: 'islamicFinance', path: '/islamic-finance',
        icon: <Icon paths={<><path d="M12 2L2 7l10 5 10-5z"/><path d="M2 17l10 5 10-5"/><path d="M12 12v10"/><path d="M7 9.5v7"/><path d="M17 9.5v7"/></>} /> },
"@

    # Insert after the dueDiligence line
    $sidebarContent = $sidebarContent -replace "(labelKey: 'dueDiligence'[^}]+\} \},)", "`$1`n$navItem"

    [System.IO.File]::WriteAllText($sidebarPath, $sidebarContent, [System.Text.Encoding]::UTF8)
    Write-Host "  [OK] Added islamicFinance to Sidebar nav (research group)" -ForegroundColor Green
}

# ============================================================
# 3. Add i18n keys to locale files
# ============================================================
Write-Host ""
Write-Host "3. Updating locale files..." -ForegroundColor Yellow

# --- ru.ts ---
$ruPath = "$ROOT\frontend\lib\locales\ru.ts"
$ruContent = Get-Content $ruPath -Raw -Encoding UTF8
if ($ruContent -match "islamicFinance") {
    Write-Host "  [SKIP] islamicFinance already in ru.ts" -ForegroundColor DarkYellow
} else {
    $ruContent = $ruContent -replace "(stockExchange: '[^']+',)", "`$1`n      islamicFinance: 'Исламские финансы',"
    [System.IO.File]::WriteAllText($ruPath, $ruContent, [System.Text.Encoding]::UTF8)
    Write-Host "  [OK] Added islamicFinance to ru.ts" -ForegroundColor Green
}

# --- en.ts ---
$enPath = "$ROOT\frontend\lib\locales\en.ts"
$enContent = Get-Content $enPath -Raw -Encoding UTF8
if ($enContent -match "islamicFinance") {
    Write-Host "  [SKIP] islamicFinance already in en.ts" -ForegroundColor DarkYellow
} else {
    $enContent = $enContent -replace "(stockExchange: '[^']+',)", "`$1`n      islamicFinance: 'Islamic Finance',"
    [System.IO.File]::WriteAllText($enPath, $enContent, [System.Text.Encoding]::UTF8)
    Write-Host "  [OK] Added islamicFinance to en.ts" -ForegroundColor Green
}

# --- uz.ts ---
$uzPath = "$ROOT\frontend\lib\locales\uz.ts"
$uzContent = Get-Content $uzPath -Raw -Encoding UTF8
if ($uzContent -match "islamicFinance") {
    Write-Host "  [SKIP] islamicFinance already in uz.ts" -ForegroundColor DarkYellow
} else {
    $uzContent = $uzContent -replace "(stockExchange: '[^']+',)", "`$1`n      islamicFinance: 'Islom moliyasi',"
    [System.IO.File]::WriteAllText($uzPath, $uzContent, [System.Text.Encoding]::UTF8)
    Write-Host "  [OK] Added islamicFinance to uz.ts" -ForegroundColor Green
}

# ============================================================
# 4. Rebuild frontend
# ============================================================
Write-Host ""
Write-Host "4. Rebuilding frontend..." -ForegroundColor Yellow
docker compose build frontend
Write-Host ""

Write-Host "5. Restarting containers..." -ForegroundColor Yellow
docker compose up -d
Write-Host ""

Write-Host "6. Waiting for frontend startup (20 sec)..." -ForegroundColor Yellow
Start-Sleep -Seconds 20

# ============================================================
# 5. Verify
# ============================================================
Write-Host ""
Write-Host "7. Verifying..." -ForegroundColor Yellow

try {
    $resp = Invoke-WebRequest -Uri "http://localhost:10000/islamic-finance" -TimeoutSec 15 -UseBasicParsing
    if ($resp.StatusCode -eq 200) {
        Write-Host "  [PASS] /islamic-finance page loads OK (HTTP 200)" -ForegroundColor Green
    } else {
        Write-Host "  [WARN] /islamic-finance returned HTTP $($resp.StatusCode)" -ForegroundColor Yellow
    }
} catch {
    Write-Host "  [INFO] Page may require login redirect - this is normal" -ForegroundColor DarkYellow
    Write-Host "  Check manually: http://localhost:10000/islamic-finance" -ForegroundColor DarkYellow
}

Write-Host ""
Write-Host "========================================" -ForegroundColor Cyan
Write-Host "  STAGE 5 FRONTEND: COMPLETE" -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan
Write-Host ""
Write-Host "New page: http://localhost:10000/islamic-finance" -ForegroundColor White
Write-Host ""
Write-Host "Features:" -ForegroundColor White
Write-Host "  Tab 1: Shariah Screening (industry + financial + full)" -ForegroundColor White
Write-Host "  Tab 2: Zakat Calculator (nisab, assets, hawl, UZ tax)" -ForegroundColor White
Write-Host "  Tab 3: Reference (haram industries, AAOIFI thresholds, indices)" -ForegroundColor White
Write-Host ""
Write-Host "Navigation: Sidebar > Research > Islamic Finance" -ForegroundColor White
Write-Host ""
Write-Host "Git commit:" -ForegroundColor Yellow
Write-Host "  git add -A"
Write-Host '  git commit -m "Stage 5 Frontend: Islamic Finance UI"'
Write-Host "  git push origin main"
